import{_ as a,o as l,c as t,a2 as r}from"./chunks/framework.BWuWLRhz.js";const _=JSON.parse('{"title":"Apple TV / 电视盒子","description":"Apple TV / 电视盒子通过路由器共享方式接入自由港机场。","frontmatter":{"description":"Apple TV / 电视盒子通过路由器共享方式接入自由港机场。"},"headers":[],"relativePath":"clients/others/apple-tv.md","filePath":"clients/others/apple-tv.md","lastUpdated":1783292109000}'),p={name:"clients/others/apple-tv.md"};function i(o,e,s,n,c,h){return l(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="apple-tv-电视盒子" tabindex="-1">Apple TV / 电视盒子 <a class="header-anchor" href="#apple-tv-电视盒子" aria-label="Permalink to &quot;Apple TV / 电视盒子&quot;">​</a></h1><p>Apple TV（tvOS）与大多数电视盒子不方便直接安装代理客户端，<strong>推荐通过路由器共享</strong>的方式接入：</p><h2 id="方案一-软路由共享-推荐" tabindex="-1">方案一：软路由共享（推荐） <a class="header-anchor" href="#方案一-软路由共享-推荐" aria-label="Permalink to &quot;方案一：软路由共享（推荐）&quot;">​</a></h2><p>在路由器上完成一次配置，Apple TV 与全屋设备即可透明接入，无需任何额外设置：</p><ol><li>按<a href="./router">路由器教程</a>在 OpenWrt 上配置 OpenClash</li><li>Apple TV 连接该路由器的 Wi-Fi 即可直接访问外网流媒体</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>这是观看 Netflix / Disney+ / YouTube 等 TV 端流媒体最稳定的方式，也不受 tvOS 应用限制。</p></div><h2 id="方案二-旁路由-网关指向" tabindex="-1">方案二：旁路由 / 网关指向 <a class="header-anchor" href="#方案二-旁路由-网关指向" aria-label="Permalink to &quot;方案二：旁路由 / 网关指向&quot;">​</a></h2><p>已有主路由不方便刷机时，可以用一台小主机 / 树莓派做旁路由：</p><ol><li>在旁路由设备上运行 Clash（如 ShellClash）</li><li>Apple TV 的网络设置中，把 <strong>路由器 / 网关和 DNS</strong> 手动指向旁路由 IP</li><li>其他设备不受影响，只有手动指向的设备走代理</li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>流媒体解锁与所选节点有关，建议选择标注支持流媒体的地区节点</li><li>TV 端播放 4K 内容对带宽要求高，建议选择低负载的香港 / 日本节点</li><li>配置过程中遇到问题，<a href="https://freedomport.cc/#/ticket" target="_blank" rel="noreferrer">提交工单</a>时请说明路由器型号和固件版本</li></ul>',11)])])}const u=a(p,[["render",i]]);export{_ as __pageData,u as default};
